sql:
SELECT hotel_location, COUNT(hotel_id) AS hotel_count
FROM hotel
GROUP BY hotel_location;

SELECT season_name, season_begin, season_end, daily_rate, weekly_rate, monthly_rate
FROM season_pricing
WHERE season_begin <= '2018-12-31' AND season_end >= '2018-01-01';

SELECT rate_id, pricing_strategy_id, rate_amount, effective_date
FROM rate
WHERE effective_date BETWEEN '2018-05-19' AND '2018-05-25';

SELECT reservation_status, COUNT(*) AS total_reservations
FROM reservation
GROUP BY reservation_status;

SELECT MAX(daily_rate) AS max_daily_rate, MIN(daily_rate) AS min_daily_rate
FROM season_pricing
WHERE daily_rate IS NOT NULL;

SELECT reservation_id, arrival_date, departure_date
FROM reservation
ORDER BY arrival_date ASC;

SELECT season_name, MAX(min_stay_days) AS max_min_stay
FROM season_pricing
GROUP BY season_name;

SELECT COUNT(*) AS booked_reservations
FROM reservation
WHERE reservation_status = 'Booked';

SELECT guest_id, points_balance
FROM guest_loyalty_program
WHERE points_balance >= 500;

SELECT room_type_name, max_occupancy
FROM room_type
WHERE max_occupancy > 1;

SELECT guest_name, guest_email
FROM guest
WHERE guest_id = 0;

SELECT COUNT(*) AS active_promotions
FROM promotion
WHERE date('now') BETWEEN promotion_start_date AND promotion_end_date;

